+/// `fchmodat2(dirfd, pathname, mode, flags)` — change file mode relative to directory fd.
+///
+/// # Safety
+///
+/// `pathname` must be a valid NUL-terminated string.
+#[inline]
+#[allow(unsafe_code)]
+pub unsafe fn sys_fchmodat2(
+    dirfd: i32,
+    pathname: *const u8,
+    mode: u32,
+    flags: i32,
+) -> Result<(), i32> {
+    let ret = unsafe {
+        raw::syscall4(
+            SYS_FCHMODAT2,
+            dirfd as usize,
+            pathname as usize,
+            mode as usize,
+            flags as usize,
+        )
+    };
+    syscall_result(ret).map(|_| ())
+}
